proof fn phi_1_temp_pred_equality_collapses_extensional(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p.pred == q.pred,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_always_unfold_suffix_equivalence(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_3_always_and_commutativity_propagates()
    ensures
        forall |p: TempPred<int>, q: TempPred<int>| always(p.and(q)) == always(q.and(p)),
{
    assert forall |p: TempPred<int>, q: TempPred<int>| always(p.and(q)) == always(q.and(p)) by {
        always_and_equality::<int>(p, q);
        always_and_equality::<int>(q, p);
        temp_pred_equality::<int>(always(p).and(always(q)), always(q).and(always(p)));
    }
}

proof fn phi_4_always_idempotent_via_external_body(p: TempPred<int>)
    requires
        valid(always(p)),
    ensures
        always(p) == always(always(p)),
{
    assert forall |ex: Execution<int>| always(always(p)).satisfied_by(ex) implies always(p).satisfied_by(ex) by {
    };
    assert forall |ex: Execution<int>| always(p).satisfied_by(ex) implies always(always(p)).satisfied_by(ex) by {
        always_unfold::<int>(ex, p);
        assert forall |i: nat| #[trigger] always(p).satisfied_by(ex.suffix(i)) by {
            assert forall |j: nat| #[trigger] p.satisfied_by(ex.suffix(i).suffix(j)) by {
                always_unfold::<int>(ex, p);
            }
        }
    };
    temp_pred_equality::<int>(always(p), always(always(p)));
}
